#include <vector>
#include <iostream>

using namespace std;

class Solution {
private:
    long long power(long long base, long long exp) {
        long long res = 1;
        base %= 1000000007;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % 1000000007;
            base = (base * base) % 1000000007;
            exp /= 2;
        }
        return res;
    }

    long long inverse(long long n) {
        return power(n, 1000000007 - 2);
    }

    vector<long long> precompute_factorials(int max_n) {
        vector<long long> fact(max_n + 1);
        vector<long long> invFact(max_n + 1);
        fact[0] = 1;
        for (int i = 1; i <= max_n; i++) {
            fact[i] = (fact[i - 1] * i) % 1000000007;
        }
        invFact[max_n] = inverse(fact[max_n]);
        for (int i = max_n - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % 1000000007;
        }
        return invFact;
    }

    long long combinations(int n, int k, const vector<long long>& invFact) {
        if (k < 0 || k > n) {
            return 0;
        }
        long long res = 1;
        for (int i = 0; i < k; ++i) {
            res = (res * (n - i)) % 1000000007;
        }
        res = (res * invFact[k]) % 1000000007;
        return res;
    }

public:
    long long solve(long long n, long long pos, long long k) {
        long long M = 1000000007;

        // Number of people to the left of pos: pos
        long long left_count = pos;
        // Number of people to the right of pos: n - 1 - pos
        long long right_count = n - 1 - pos;

        // The observer at 'pos' does not influence the visibility count k.
        // This person can choose 'L' or 'R', contributing a factor of 2 to the total count.
        long long ans_pos_choices = 2;

        // We need to choose 'k_L' people from the left side (size 'left_count') 
        // to choose 'L' such that they are visible.
        // Visibility for i < pos: visible iff person i chooses 'L'.
        // So, we need exactly k_L people from the left to choose 'L'.
        // Number of ways to choose k_L from left_count: C(left_count, k_L)

        // We need to choose 'k_R' people from the right side (size 'right_count') 
        // to choose 'R' such that they are visible.
        // Visibility for i > pos: visible iff person i chooses 'R'.
        // So, we need exactly k_R people from the right to choose 'R'.
        // Number of ways to choose k_R from right_count: C(right_count, k_R)

        // Total required visible people: k_L + k_R = k.

        // We iterate over all possible number of visible people from the left side, k_L.
        // 0 <= k_L <= left_count
        // k_R = k - k_L
        // We must also have 0 <= k_R <= right_count

        long long total_ways = 0;

        // Precompute factorials and inverse factorials for combinations calculation.
        // Max size needed is n.
        vector<long long> invFact = precompute_factorials(n);

        for (long long k_L = 0; k_L <= left_count; ++k_L) {
            long long k_R = k - k_L;

            if (k_R >= 0 && k_R <= right_count) {
                // Ways to achieve k_L visible from left: C(left_count, k_L)
                long long ways_L = combinations(left_count, k_L, invFact);

                // Ways to achieve k_R visible from right: C(right_count, k_R)
                long long ways_R = combinations(right_count, k_R, invFact);

                // Number of ways for this specific split (k_L, k_R): ways_L * ways_R
                long long ways_split = (ways_L * ways_R) % M;

                total_ways = (total_ways + ways_split) % M;
            }
        }

        // The total answer is (Total ways to satisfy k) * (Ways for person at pos)
        return (total_ways * ans_pos_choices) % M;
    }
};
