    long long MOD = 1000000007;

    // Number of people to the left of pos (indices 0 to pos - 1)
    int L = pos;
    // Number of people to the right of pos (indices pos + 1 to n - 1)
    int R = n - 1 - pos;

    // The visibility count is determined by:
    // 1. People to the left (i < pos): Visible if they choose 'L'.
    //    There are L such people. Let x be the number of them choosing 'L'.
    //    x must be between 0 and L.
    // 2. People to the right (i > pos): Visible if they choose 'R'.
    //    There are R such people. Let y be the number of them choosing 'R'.
    //    y must be between 0 and R.
    // 3. The person at pos: Their choice ('L' or 'R') does not affect the count k.

    // We need x + y = k.

    // We iterate over the possible number of left viewers, x.
    // x must satisfy:
    // 1. 0 <= x <= L
    // 2. 0 <= k - x <= R  =>  k - R <= x <= k

    // Combining constraints for x:
    // max(0, k - R) <= x <= min(L, k)

    long long total_ways = 0;

    // Iterate x from the lower bound to the upper bound
    int start_x = max(0, (int)(k - R));
    int end_x = min(L, (int)k);

    for (int x = start_x; x <= end_x; ++x) {
        // If x people on the left see pos (i.e., choose 'L'):
        // The number of ways to choose these x people from L is C(L, x).
        long long ways_left = combinations(L, x);

        // If x people are visible from the left, then y = k - x people must be visible from the right.
        int y = (int)(k - x);

        // The number of ways to choose these y people from R is C(R, y).
        long long ways_right = combinations(R, y);

        // The number of ways to set directions for people other than pos, 
        // satisfying the count k, is ways_left * ways_right.
        long long ways_others = (ways_left * ways_right) % MOD;

        // The person at pos can choose 'L' or 'R' (2 options), independent of the visibility count k.
        // Total ways for this fixed x is ways_others * 2.
        long long current_ways = (ways_others * 2) % MOD;

        total_ways = (total_ways + current_ways) % MOD;
    }

    return total_ways;
}
